#include <iostream>
#include <sstream>

class Point {
public:
    int x;
    int y;

    Point(int _x = 0, int _y = 0) : x(_x), y(_y) {}

    friend std::ostream& operator<<(std::ostream& os, const Point& p) {
        os << "(" << p.x << ", " << p.y << ")";
        return os;
    }

    Point& operator++() {
        x++;
        y++;
        return *this;
    }
}; // Corrected Point class definition for driver context

int main() {
    std::stringstream ss;

    // Test Case 1: Basic increment
    Point p1(1, 2);
    ss << "Initial p1: " << p1 << std::endl;
    ++p1;
    ss << "After ++p1: " << p1 << std::endl;

    // Test Case 2: Return value of prefix increment
    Point p2(5, 5);
    Point& ref_p2 = ++p2;
    ss << "After ++p2, p2: " << p2 << std::endl;
    ss << "Reference ref_p2: " << ref_p2 << std::endl;
    ref_p2.x = 10;
    ss << "After ref_p2.x = 10, p2: " << p2 << std::endl;

    // Test Case 3: Chained increment
    Point p3(10, 20);
    ss << "Initial p3: " << p3 << std::endl;
    ++(++p3);
    ss << "After ++(++p3): " << p3 << std::endl;

    std::cout << ss.str();
    return 0;
}
